import{_ as n,c as i,o as t,a1 as a}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Erweiterte Funktionen: Multi-Account-Verwaltung | Antigravity Auth","description":"Beherrschen Sie die erweiterten Funktionen des Antigravity Auth-Plugins. Vertiefen Sie Ihr Wissen über Kernmechanismen wie Multi-Account-Load-Balancing, intelligente Account-Auswahl, Ratenbegrenzungsbehandlung, Sitzungswiederherstellung und Anfragetransformation.","frontmatter":{"title":"Erweiterte Funktionen: Multi-Account-Verwaltung | Antigravity Auth","sidebarTitle":"Multi-Account-Master","subtitle":"Erweiterte Funktionen: Multi-Account-Verwaltung","description":"Beherrschen Sie die erweiterten Funktionen des Antigravity Auth-Plugins. Vertiefen Sie Ihr Wissen über Kernmechanismen wie Multi-Account-Load-Balancing, intelligente Account-Auswahl, Ratenbegrenzungsbehandlung, Sitzungswiederherstellung und Anfragetransformation.","order":3},"headers":[],"relativePath":"de/NoeFabris/opencode-antigravity-auth/advanced/index.md","filePath":"de/NoeFabris/opencode-antigravity-auth/advanced/index.md"}'),r={name:"de/NoeFabris/opencode-antigravity-auth/advanced/index.md"};function l(u,e,o,s,h,d){return t(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="erweiterte-funktionen" tabindex="-1">Erweiterte Funktionen <a class="header-anchor" href="#erweiterte-funktionen" aria-label="Permalink to &quot;Erweiterte Funktionen&quot;">​</a></h1><p>Dieses Kapitel hilft Ihnen, die erweiterten Funktionen des Antigravity Auth-Plugins tiefgreifend zu beherrschen, einschließlich Multi-Account-Load-Balancing, intelligenter Account-Auswahl, Ratenbegrenzungsbehandlung, Sitzungswiederherstellung, Anfragetransformation und anderen Kernmechanismen. Ob Sie die Quota-Auslastung optimieren oder komplexe Probleme beheben möchten – hier finden Sie die Antworten, die Sie benötigen.</p><h2 id="voraussetzungen" tabindex="-1">Voraussetzungen <a class="header-anchor" href="#voraussetzungen" aria-label="Permalink to &quot;Voraussetzungen&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Stellen Sie vor dem Start sicher, dass</p><ul><li>✅ Sie die <a href="./../start/quick-install/">Schnellinstallation</a> abgeschlossen und Ihren ersten Account erfolgreich hinzugefügt haben</li><li>✅ Sie die <a href="./../start/first-auth-login/">erste Authentifizierung</a> durchgeführt und den OAuth-Ablauf verstanden haben</li><li>✅ Sie die <a href="./../start/first-request/">erste Anfrage</a> gesendet und die korrekte Funktionsweise des Plugins verifiziert haben</li></ul></div><h2 id="lernpfad" tabindex="-1">Lernpfad <a class="header-anchor" href="#lernpfad" aria-label="Permalink to &quot;Lernpfad&quot;">​</a></h2><h3 id="_1-multi-account-einrichtung" tabindex="-1">1. <a href="./multi-account-setup/">Multi-Account-Einrichtung</a> <a class="header-anchor" href="#_1-multi-account-einrichtung" aria-label="Permalink to &quot;1. [Multi-Account-Einrichtung](./multi-account-setup/)&quot;">​</a></h3><p>Konfigurieren Sie mehrere Google-Accounts, um Quota-Pooling und Load-Balancing zu implementieren.</p><ul><li>Fügen Sie mehrere Accounts hinzu, um die Gesamtobergrenze für Quota zu erhöhen</li><li>Verstehen Sie das doppelte Quota-System (Antigravity + Gemini CLI)</li><li>Wählen Sie die passende Anzahl an Accounts basierend auf Ihrem Anwendungsfall</li></ul><h3 id="_2-account-auswahlstrategien" tabindex="-1">2. <a href="./account-selection-strategies/">Account-Auswahlstrategien</a> <a class="header-anchor" href="#_2-account-auswahlstrategien" aria-label="Permalink to &quot;2. [Account-Auswahlstrategien](./account-selection-strategies/)&quot;">​</a></h3><p>Beherrschen Sie die bewährten Verfahren für die drei Account-Auswahlstrategien: sticky, round-robin und hybrid.</p><ul><li>1 Account → sticky-Strategie behält Prompt-Cache bei</li><li>2-3 Accounts → hybrid-Strategie verteilt Anfragen intelligent</li><li>4+ Accounts → round-robin-Strategie maximiert Durchsatz</li></ul><h3 id="_3-ratenbegrenzungsbehandlung" tabindex="-1">3. <a href="./rate-limit-handling/">Ratenbegrenzungsbehandlung</a> <a class="header-anchor" href="#_3-ratenbegrenzungsbehandlung" aria-label="Permalink to &quot;3. [Ratenbegrenzungsbehandlung](./rate-limit-handling/)&quot;">​</a></h3><p>Verstehen Sie die Erkennung von Ratenbegrenzungen, automatische Wiederholungen und Account-Wechselmechanismen.</p><ul><li>Unterscheiden Sie 5 verschiedene Typen von 429-Fehlern</li><li>Verstehen Sie den exponentiellen Backoff-Algorithmus für automatische Wiederholungen</li><li>Beherrschen Sie die automatische Umschaltlogik in Multi-Account-Szenarien</li></ul><h3 id="_4-sitzungswiederherstellung" tabindex="-1">4. <a href="./session-recovery/">Sitzungswiederherstellung</a> <a class="header-anchor" href="#_4-sitzungswiederherstellung" aria-label="Permalink to &quot;4. [Sitzungswiederherstellung](./session-recovery/)&quot;">​</a></h3><p>Erfahren Sie mehr über den Sitzungswiederherstellungsmechanismus zur automatischen Behandlung von Tool-Aufruffehlern und Unterbrechungen.</p><ul><li>Automatische Behandlung von tool_result_missing-Fehlern</li><li>Behebung von thinking_block_order-Problemen</li><li>Konfiguration der Optionen auto_resume und session_recovery</li></ul><h3 id="_5-anfragetransformationsmechanismus" tabindex="-1">5. <a href="./request-transformation/">Anfragetransformationsmechanismus</a> <a class="header-anchor" href="#_5-anfragetransformationsmechanismus" aria-label="Permalink to &quot;5. [Anfragetransformationsmechanismus](./request-transformation/)&quot;">​</a></h3><p>Verstehen Sie tiefgreifend den Anfragetransformationsmechanismus und wie er Protokollunterschiede verschiedener KI-Modelle kompatibel macht.</p><ul><li>Verstehen Sie die Protokollunterschiede zwischen Claude- und Gemini-Modellen</li><li>Beheben Sie 400-Fehler durch Schema-Inkompatibilitäten</li><li>Optimieren Sie die Thinking-Konfiguration für beste Leistung</li></ul><h3 id="_6-konfigurationsleitfaden" tabindex="-1">6. <a href="./configuration-guide/">Konfigurationsleitfaden</a> <a class="header-anchor" href="#_6-konfigurationsleitfaden" aria-label="Permalink to &quot;6. [Konfigurationsleitfaden](./configuration-guide/)&quot;">​</a></h3><p>Beherrschen Sie alle Konfigurationsoptionen und passen Sie das Plugin-Verhalten nach Bedarf an.</p><ul><li>Speicherort und Priorität der Konfigurationsdatei</li><li>Einstellungen für Modellverhalten, Account-Rotation und Anwendungsverhalten</li><li>Empfohlene Konfigurationen für Single-Account/Multi-Account/Parallel-Agent-Szenarien</li></ul><h3 id="_7-parallel-agent-optimierung" tabindex="-1">7. <a href="./parallel-agents/">Parallel-Agent-Optimierung</a> <a class="header-anchor" href="#_7-parallel-agent-optimierung" aria-label="Permalink to &quot;7. [Parallel-Agent-Optimierung](./parallel-agents/)&quot;">​</a></h3><p>Optimieren Sie die Account-Zuweisung für Parallel-Agent-Szenarien und aktivieren Sie PID-Offset.</p><ul><li>Verstehen Sie Account-Konflikte in Parallel-Agent-Szenarien</li><li>Aktivieren Sie PID-Offset, damit verschiedene Prozesses bevorzugt verschiedene Accounts auswählen</li><li>Kombinieren Sie mit der round-robin-Strategie, um die Multi-Account-Nutzung zu maximieren</li></ul><h3 id="_8-debug-logging" tabindex="-1">8. <a href="./debug-logging/">Debug-Logging</a> <a class="header-anchor" href="#_8-debug-logging" aria-label="Permalink to &quot;8. [Debug-Logging](./debug-logging/)&quot;">​</a></h3><p>Aktivieren Sie Debug-Logs, um Probleme zu beheben und den Laufzeitstatus zu überwachen.</p><ul><li>Aktivieren Sie Debug-Logging für detaillierte Informationen</li><li>Verstehen Sie verschiedene Log-Levels und deren Anwendungsgebiete</li><li>Interpretieren Sie Log-Inhalte, um Probleme schnell zu lokalisieren</li></ul><h2 id="nachste-schritte" tabindex="-1">Nächste Schritte <a class="header-anchor" href="#nachste-schritte" aria-label="Permalink to &quot;Nächste Schritte&quot;">​</a></h2><p>Nach Abschluss der erweiterten Funktionen können Sie:</p><ul><li>📖 In den <a href="./../faq/">Häufig gestellten Fragen</a> Lösungen für Probleme bei der Nutzung finden</li><li>📚 Im <a href="./../appendix/">Anhang</a> mehr über Architekturdesign und vollständige Konfigurationsreferenz lesen</li><li>🔄 Im <a href="./../changelog/">Änderungsprotokoll</a> die neuesten Funktionen und Änderungen verfolgen</li></ul>',32)])])}const f=n(r,[["render",l]]);export{g as __pageData,f as default};
